const path = require('path');

async function loadPlugin(pluginConfig) {
    let pluginModule;
    try {
        if (!pluginConfig || !pluginConfig.type || !pluginConfig.source) {
            throw new Error('Invalid plugin configuration: type and source are required.');
        }

        switch (pluginConfig.type) {
            case 'require':
                // Resolve path relative to current working directory
                const modulePath = path.resolve(process.cwd(), pluginConfig.source);
                // Invalidate cache to allow live reloading of plugins in development
                delete require.cache[require.resolve(modulePath)];
                pluginModule = require(modulePath);
                break;
            case 'eval':
                // DANGER: Executing arbitrary code from eval() is a severe security risk.
                // Ensure `pluginConfig.source` comes from a trusted source.
                pluginModule = eval(pluginConfig.source);
                break;
            default:
                throw new Error(`Unsupported plugin type: ${pluginConfig.type}. Must be 'require' or 'eval'.`);
        }

        if (typeof pluginModule !== 'object' || pluginModule === null) {
            throw new Error('Plugin must export or evaluate to an object.');
        }

        console.log(`Plugin '${pluginModule.name || pluginConfig.name || 'Unnamed'}' loaded successfully.`);
        return pluginModule;

    } catch (error) {
        console.error(`Error loading plugin '${pluginConfig.name || 'Unnamed'}' (${pluginConfig.type}):`, error.message);
        throw error;
    }
}

module.exports = { loadPlugin };

